CREATE TABLE app_accounts ( id BIGINT NOT NULL, serial_id VARCHAR(50) UNIQUE NOT NULL, owner_id VARCHAR(50) NOT NULL, account_name character varying(80) NOT NULL, company_type VARCHAR(20) , tax_identification_number VARCHAR(50), commercial_registry VARCHAR(50), address VARCHAR(100), phone VARCHAR(30), email VARCHAR(50), website VARCHAR(50), currency_id integer , parent_id BIGINT , partner_id BIGINT , state_id INTEGER, country_id INTEGER, account_color varchar(10),
default_receivable_account_id Integer, default_payable_account_id Integer,
created_by character varying(50) , created_date timestamp(6) without time zone NOT NULL, last_modified_by character varying(50) , last_modified_date timestamp(6) without time zone, deleted_by character varying(50) , deleted_date timestamp(6) without time zone, is_delete boolean DEFAULT false,
CONSTRAINT fk_account_default_ar FOREIGN KEY (default_receivable_account_id) REFERENCES fin_accounts(id),
CONSTRAINT fk_account_default_ap FOREIGN KEY (default_payable_account_id) REFERENCES fin_accounts(id), CONSTRAINT app_accounts_p_key PRIMARY KEY (id) );
CREATE SEQUENCE app_accounts_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY app_accounts.id;
INSERT INTO app_accounts( id, account_name, company_type, serial_id, partner_id, currency_id, owner_id, created_by , created_date , last_modified_by , last_modified_date ) VALUES ( nextval('app_accounts_id_seq') , 'ISolution APP', 'SYSTEM', 'AC0000000001' , 1, 1, '01110010908', '01110010908' ,CURRENT_TIMESTAMP, '01110010908' ,CURRENT_TIMESTAMP );
